-- FUNCTION: public.fn_utilization_get_level(integer, character varying)

-- DROP FUNCTION IF EXISTS public.fn_utilization_get_level(integer, character varying);

CREATE OR REPLACE FUNCTION public.fn_utilization_get_level(
p_system_id integer,
p_entity_type character varying)
RETURNS record
LANGUAGE 'plpgsql'
COST 100
VOLATILE PARALLEL UNSAFE
AS 
B
O
D
Y

DECLARE
v_arow_utilization record;
v_arow_entity_details record;
v_layer_table character varying;
v_layer_id integer;
v_used_port integer;
v_utilization_level character varying;
v_total_ports integer;
v_current_utilization double precision;
v_utilization record;
v_geom_type character varying;
v_utilization_abbr character varying;
v_message_prefix character varying;
sql character varying;
BEGIN
v_used_port:=0;
v_message_prefix:='Ports';

select layer_table,geom_type,layer_id into v_layer_table,v_geom_type,v_layer_id from layer_details where upper(layer_name)=upper(p_entity_type);
sql:='select * from '||v_layer_table||' where system_id='||p_system_id||' ';
execute sql into v_arow_entity_details;

select * into v_arow_utilization from entity_utilization_settings
where (layer_id=v_layer_id and region_id=v_arow_entity_details.region_id
and province_id=v_arow_entity_details.province_id
and network_status=v_arow_entity_details.network_status) or is_default=true order by layer_id desc limit 1;

select count(1) into v_used_port from(
select source_system_id,source_entity_type,source_port_no from connection_info where upper(source_entity_type)!=upper(destination_entity_type)
and (source_system_id=p_system_id and upper(source_entity_type)=upper(p_entity_type) and source_port_no>0 and is_through_connection = false)
union
select destination_system_id,destination_entity_type,destination_port_no from connection_info where upper(source_entity_type)!=upper(destination_entity_type)
and(destination_system_id=p_system_id and upper(destination_entity_type)=upper(p_entity_type) and destination_port_no>0 and is_through_connection = false)) a;

if(upper(v_geom_type)='LINE')
then
-- select count(1) into v_used_port from att_details_cable_info where cable_id=p_system_id and (a_end_status_id=2 or b_end_status_id=2);
select count(1) into v_total_ports from att_details_cable_info where cable_id=p_system_id;
v_message_prefix:='Cores';
else
select (case when SPLIT_PART(no_of_ports, ':', 2)!='' then SPLIT_PART(no_of_ports, ':', 2)::integer else no_of_ports::integer end)
into v_total_ports from point_master where system_id=p_system_id and upper(entity_type)=upper(p_entity_type);
end if;

if(v_total_ports>0)
then
v_current_utilization:=((v_used_port::double precision/v_total_ports::double precision)*100);
end if;

v_utilization_level:=v_message_prefix||' are low utilized.';
v_utilization_abbr:='L';

RAISE INFO 'v_current_utilization%', v_current_utilization;

if(v_current_utilization>=v_arow_utilization.utilization_range_low_from and v_current_utilization<=v_arow_utilization.utilization_range_low_to)
then
v_utilization_level:=' are low utilized.';
v_utilization_abbr:='L';
elsif(v_current_utilization>=v_arow_utilization.utilization_range_moderate_from and v_current_utilization<=v_arow_utilization.utilization_range_moderate_to)
then
v_utilization_level:=' are medium utilized.';
v_utilization_abbr:='M';
elsif(v_current_utilization>=v_arow_utilization.utilization_range_high_from and v_current_utilization<=v_arow_utilization.utilization_range_high_to)
then

v_utilization_level:=v_message_prefix||' are highly utilized.';
v_utilization_abbr:='H';
elsif(v_current_utilization>=v_arow_utilization.utilization_range_over_from and (v_current_utilization<=v_arow_utilization.utilization_range_over_to
or v_current_utilization>v_arow_utilization.utilization_range_over_to))
then
v_utilization_level:=v_message_prefix||' are over utilized';
v_utilization_abbr:='O';
end if;
select v_utilization_abbr,v_utilization_level,v_total_ports,v_used_port,v_arow_entity_details.region_id,v_arow_entity_details.province_id into v_utilization;
return v_utilization;
END
B
O
D
Y
;

ALTER FUNCTION public.fn_utilization_get_level(integer, character varying)
OWNER TO postgres;
