CREATE OR REPLACE FUNCTION public.fn_trg_update_entity_attribute()
RETURNS trigger
LANGUAGE plpgsql
AS 
f
u
n
c
t
i
o
n

declare
v_layer_name character varying;
v_is_virtual boolean;
v_display_value character varying;
v_is_updated boolean;
v_display_name character varying;
v_new_display_name character varying;
v_old_display_name character varying;
v_entity_category character varying;
v_column_name character varying;
v_geom_type character varying;
_value integer;
_ignorecol character varying;
_ignorecol1 character varying;

BEGIN
v_is_updated:=false;
select layer_name,geom_type into v_layer_name,v_geom_type from layer_details where upper(layer_table)=upper(TG_TABLE_NAME::regclass::text);

IF (TG_OP = 'INSERT')
THEN
-- IF EXISTS(SELECT 1 FROM information_schema.columns WHERE upper(table_name)=upper(TG_TABLE_NAME::regclass::text) and upper(column_name)=upper('is_visible_on_map'))
-- AND EXISTS(SELECT 1 FROM information_schema.columns WHERE upper(table_name)=upper(TG_TABLE_NAME::regclass::text) and upper(column_name)=upper('source_ref_id'))
-- THEN
-- if(coalesce(new.source_ref_id,'')!='')
-- then
-- execute 'update '||TG_TABLE_NAME||' set is_visible_on_map=false where system_id='||new.system_id||'';
-- end if;
-- END IF;
END IF;

IF (TG_OP = 'UPDATE')
THEN
_ignorecol := 'modified_on,gis_design_id,codification_sequence,codification_sequence,area_system_id,area_id,subarea_system_id,subarea_id,dsa_system_id,dsa_id,csa_system_id,csa_id';
_ignorecol1 := 'modified_by';
SELECT fn_check_history_record(OLD, NEW,_ignorecol,_ignorecol1) INTO _value;
IF(_value = 1)THEN
-- IF EXISTS(SELECT 1 FROM information_schema.columns WHERE upper(table_name)=upper(TG_TABLE_NAME::regclass::text) and upper(column_name)=upper('is_visible_on_map'))
-- AND EXISTS(SELECT 1 FROM information_schema.columns WHERE upper(table_name)=upper(TG_TABLE_NAME::regclass::text) and upper(column_name)=upper('source_ref_id'))
-- AND EXISTS(SELECT 1 FROM information_schema.columns WHERE upper(table_name)=upper(TG_TABLE_NAME::regclass::text) and upper(column_name)=upper('is_new_entity'))
-- THEN
-- if(coalesce(new.source_ref_id,'')!='' and new.is_new_entity=true)
-- then
-- execute 'update '||TG_TABLE_NAME||' set is_visible_on_map=false where system_id='||new.system_id||'';
-- end if;
-- END IF;

select clabel.display_column_name into v_display_name from display_name_settings clabel
inner join layer_details ld on clabel.layer_id=ld.layer_id where upper(ld.layer_name)=upper(v_layer_name);
	
IF(coalesce(v_display_name,'')!='')
then	
	if(v_layer_name!='POD')
	then
	EXECUTE 'SELECT $1.' || v_display_name USING NEW INTO v_new_display_name;
	EXECUTE 'SELECT $1.' || v_display_name USING OLD INTO v_old_display_name;
	v_is_updated:=(upper(v_new_display_name)!=upper(v_old_display_name));		
	end if;

	if(v_layer_name='POD')
	then
		v_is_updated:=true;
	end if;
	
	--v_display_name:=replace(v_display_name,"$1.",'');
	if(v_is_updated)
	then 
		execute 'select '||v_display_name||' from '||TG_TABLE_NAME||' where system_id='||new.system_id||'' into v_display_value; 
		update connection_info set source_display_name=v_display_value where source_system_id=new.system_id and upper(source_entity_type)=upper(v_layer_name);
		update connection_info set destination_display_name=v_display_value where destination_system_id=new.system_id and upper(destination_entity_type)=upper(v_layer_name);
	        execute 'update '||v_geom_type||'_master set display_name='''||v_display_value||''' where system_id='||new.system_id||' and upper(entity_type)=upper('''||v_layer_name||''')';
	        execute 'update associate_entity_info set entity_display_name='''||v_display_value||''' where entity_system_id='||new.system_id||' and upper(entity_type)=upper('''||v_layer_name||''')';
	        execute 'update associate_entity_info set associated_display_name='''||v_display_value||''' where associated_system_id='||new.system_id||' and upper(associated_entity_type)=upper('''||v_layer_name||''')';
		execute 'update isp_line_master set display_name='''||v_display_value||''' where entity_id='||new.system_id||' and upper(entity_type)=upper('''||v_layer_name||''')';	
	end if;
    end if;

IF EXISTS(SELECT 1 FROM information_schema.columns WHERE upper(table_name)=upper(TG_TABLE_NAME::regclass::text) and upper(column_name)=upper('is_buried'))
THEN
	if(new.is_buried!=old.is_buried)
	then
		update point_master set is_buried=new.is_buried where system_id=new.system_id and upper(entity_type)=upper(v_layer_name);
	end if;
END IF;

IF EXISTS(SELECT 1 FROM information_schema.columns WHERE upper(table_name)=upper(TG_TABLE_NAME::regclass::text) and upper(column_name)=upper('is_virtual'))
THEN
	if(new.is_virtual!=old.is_virtual)
	then
		update point_master set is_virtual=new.is_virtual where system_id=new.system_id and upper(entity_type)=upper(v_layer_name);
	end if;
    END IF;

IF EXISTS(SELECT 1 FROM information_schema.columns WHERE upper(table_name)=upper(TG_TABLE_NAME::regclass::text) and (upper(column_name)=upper('splitter_type') or upper(column_name)=upper('entity_category')))
THEN
	v_column_name:=(case when upper(v_layer_name)=upper('Splitter') then 'splitter_type' else 'entity_category' end);
	execute 'select '||v_column_name||'  from '||TG_TABLE_NAME::regclass::text||' where system_id='||new.system_id||' ' into v_entity_category;
	update point_master set entity_category=v_entity_category where system_id=new.system_id and upper(entity_type)=upper(v_layer_name);
    END IF;
 
IF EXISTS(SELECT 1 FROM information_schema.columns WHERE upper(table_name)=upper(TG_TABLE_NAME::regclass::text) and upper(column_name)=upper('project_id'))
THEN
	if(new.project_id!=old.project_id)
	then
		update point_master set project_id=new.project_id where system_id=new.system_id and upper(entity_type)=upper(v_layer_name);
	    update line_master set project_id=new.project_id where system_id=new.system_id and upper(entity_type)=upper(v_layer_name);
	    update polygon_master set project_id=new.project_id where system_id=new.system_id and upper(entity_type)=upper(v_layer_name);
	end if;
    END IF;
END IF;
END IF;
RETURN NEW;
END;
f
u
n
c
t
i
o
n

;

drop view vw_att_details_fiber_link;

CREATE OR REPLACE VIEW public.vw_att_details_fiber_link
AS SELECT link.system_id,
link.link_id,
link.link_name,
link.link_type,
link.network_id,
link.start_point_type,
link.start_point_network_id,
link.start_point_location,
link.end_point_type,
link.end_point_network_id,
link.end_point_location,
link.no_of_lmc,
link.each_lmc_length,
link.total_route_length,
link.gis_length,
link.otdr_distance,
link.no_of_pair,
link.tube_and_core_details,
link.existing_route_length_otdr,
link.new_building_route_length,
link.otm_length,
link.otl_length,
CASE
WHEN link.any_row_portion = true THEN 'Yes'::text
ELSE 'No'::text
END AS any_row_portion,
link.row_authority,
link.total_row_segments,
link.total_row_length,
link.total_row_reccuring_charges,
fn_get_date(link.handover_date, false) AS handover_date,
fn_get_date(link.hoto_signoff_date, false) AS hoto_signoff_date,
link.fiber_link_status,
link.remarks,
um.user_name AS created_by,
fn_get_date(link.created_on) AS created_on,
fn_get_date(link.modified_on) AS modified_on,
um2.user_name AS modified_by,
um.user_id AS created_by_id,
link.service_id,
link.main_link_type,
link.main_link_id,
link.redundant_link_type,
link.redundant_link_id
--pm1.latitude AS start_point_latitude,
--pm1.longitude AS start_point_longitude,
--pm2.latitude AS end_point_latitude,
--pm2.longitude AS end_point_longitude,
--cbl.status,
--cbl.region_id,
--cbl.province_id,
--fn_get_network_status(cbl.network_status) AS network_status
FROM att_details_fiber_link link
JOIN user_master um ON link.created_by = um.user_id
LEFT JOIN user_master um2 ON link.modified_by = um2.user_id;
